import{_ as i,o as a,i as s,a9 as t}from"./chunks/framework.D47vmB0i.js";const u=JSON.parse('{"title":"Security","description":"Guard CSV exports against spreadsheet formula injection with one option.","frontmatter":{"description":"Guard CSV exports against spreadsheet formula injection with one option."},"headers":[],"relativePath":"guide/security.md","filePath":"guide/security.md","lastUpdated":1781644290000}'),r={name:"guide/security.md"};function n(l,e,o,h,p,d){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="formula-injection" tabindex="-1">Formula injection <a class="header-anchor" href="#formula-injection" aria-label="Permalink to &quot;Formula injection&quot;">​</a></h2><p>csv-pipe produces RFC 4180-compliant text. By default it does not neutralize values that a spreadsheet application may interpret as a formula (for example a cell beginning with <code>=</code>, <code>+</code>, <code>-</code>, <code>@</code>, a tab, or a carriage return).</p><p>When you export untrusted data for use in spreadsheets, enable the built-in guard:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rows, { sanitizeFormulas: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// A cell like =1+1 is written as &#39;=1+1, so the spreadsheet shows it literally.</span></span></code></pre></div><p>It prefixes any string or array cell that begins with a formula character so the value is shown literally. Numbers, booleans, and dates are never altered. The prefix defaults to a single quote and can be changed with <code>formulaPrefix</code>:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(rows, { sanitizeFormulas: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, formulaPrefix: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span></code></pre></div><p>On the parsing side a cell that looks like a formula (for example <code>=1+1</code>) is returned as a plain string; csv-pipe never evaluates it. The guard matters when you re-export parsed, untrusted data, so set <code>sanitizeFormulas</code> on that export.</p><h2 id="reporting-a-vulnerability" tabindex="-1">Reporting a vulnerability <a class="header-anchor" href="#reporting-a-vulnerability" aria-label="Permalink to &quot;Reporting a vulnerability&quot;">​</a></h2><p>Please report security issues privately through GitHub&#39;s <a href="https://github.com/martsinlabs/csv-pipe/security/advisories/new" target="_blank" rel="noreferrer">private vulnerability reporting</a>, not as a public issue. See the <a href="https://github.com/martsinlabs/csv-pipe/blob/master/SECURITY.md" target="_blank" rel="noreferrer">security policy</a> for details.</p>`,10)])])}const k=i(r,[["render",n]]);export{u as __pageData,k as default};
